 * Create a new local site
 */
nexusSitesCreate: async (_parent, { input }) => {
    return (0, resolver_utils_1.withQueue)(async () => {
        try {
            if (!services.localServices) {
                return {
                    success: false,
                    error: 'Local services not available',
                };
            }
            const result = await services.localServices.createSite({
                name: input.name,
                phpVersion: input.phpVersion,
            });
            return {
                success: true,
                siteName: result.name,
                siteId: result.id,
                siteDomain: result.domain,
            };
        }
        catch (error) {
            return {
                success: false,
                error: error.message,
            };
        }
    });

